const body = $input.first().json.body;

// Suporta duas estruturas: direta e aninhada em data
const data = body?.data || body;
const key = data?.key || {};

const remoteJid = key?.remoteJid || body?.remoteJid || '';
const phone = remoteJid.replace('@s.whatsapp.net', '') || '';
const pushName = data?.pushName || body?.pushName || '';
const instanceName = body?.instance || body?.instanceName || '';
const isFromMe = key?.fromMe || body?.fromMe || false;
const event = body?.event || '';

if (isFromMe) throw new Error('Message from me - ignore');

if (remoteJid?.endsWith('@g.us') || 
    remoteJid?.endsWith('@lid') ||
    remoteJid === 'status@broadcast') {
  throw new Error('Group/broadcast/lid message - ignore');
}

const allowedEvents = ['messages.upsert', 'messages.update'];
if (event && !allowedEvents.includes(event)) {
  throw new Error('System event ignored: ' + event);
}

const ALLOWED_NUMBERS = [
  '5521972892504',
  '5521983527590',
  '5521972892514',
  '5511912361577',
  '5583996700266',
  '5592991433073',
  '5579999521502',
  '5569984587715',
  '5585991550675'
];
if (!ALLOWED_NUMBERS.includes(phone)) {
  throw new Error('Not a test number - ignore');
}

const isAudio = data?.messageType === 'audioMessage' || 
                !!data?.message?.audioMessage;

const messageId = isAudio ? (key?.id || '') : '';

const message = data?.message?.conversation || 
                data?.message?.extendedTextMessage?.text || 
                body?.chatInput || '';

if (!message && !isAudio) {
  throw new Error('No text message - ignore');
}

return [{
  json: {
    phone,
    message,
    pushName,
    instanceName,
    isAudio,
    messageId
  }
}];

