const base64 = $input.first().json.base64;

// Calcula tamanho aproximado em bytes a partir do base64
const fileSize = Math.round((base64.length * 3) / 4);

return [{
  json: $input.first().json,
  binary: {
    audio: {
      data: base64,
      mimeType: 'audio/ogg',
      fileName: 'audio.ogg',
      fileSize: fileSize
    }
  }
}];

const raw = $input.first().json.choices[0].message.content || '';

let resposta = raw;
let classificacao = 'cold';

try {
  const parsed = JSON.parse(raw);
  // Se não existir a chave, força para vazio ao invés de devolver o RAW "cru"
  resposta = parsed.resposta_whatsapp || parsed.resposta || "";
  classificacao = parsed.classificacao_lead || parsed.classificacao || 'cold';
} catch(e) {
  resposta = raw;
  const match = raw.match(/\b(cold|warm|hot|active_client)\b/i);
  classificacao = match ? match[1].toLowerCase() : 'cold';
}

const validClass = ['cold', 'warm', 'hot', 'active_client'];
if (!validClass.includes(classificacao)) classificacao = 'cold';

// Detectar tags de mídia e escalada antes de limpar
const enviarFotoProduto = resposta.includes('##ENVIAR_FOTO_PRODUTO##');
const enviarDossie = resposta.includes('##ENVIAR_DOSSIE##');
const enviarVideoEntrega = resposta.includes('##ENVIAR_VIDEO_ENTREGA##');
const precisaEscalar = resposta.includes('##ESCALAR##');

// Remover tags da resposta de texto
let respostaLimpa = resposta
  .replace(/##ENVIAR_FOTO_PRODUTO##/g, '')
  .replace(/##ENVIAR_DOSSIE##/g, '')
  .replace(/##ENVIAR_VIDEO_ENTREGA##/g, '')
  .replace(/##ESCALAR##/g, '')
  .trim();

// TRAVA DE SEGURANÇA: Se a IA devolver chaves puras, zera a resposta
if (respostaLimpa === "{}" || respostaLimpa === "{\n}") {
  respostaLimpa = "";
}

// Versão para salvar no histórico — com marcadores de mídia
const respostaHistorico = resposta
  .replace(/##ENVIAR_FOTO_PRODUTO##/g, '[foto_enviada]')
  .replace(/##ENVIAR_DOSSIE##/g, '[dossie_enviado]')
  .replace(/##ENVIAR_VIDEO_ENTREGA##/g, '[video_entrega_enviado]')
  .replace(/##ESCALAR##/g, '')
  .trim();

return [{ json: { 
  resposta: respostaLimpa, 
  respostaHistorico,
  classificacao,
  enviarFotoProduto,
  enviarDossie,
  enviarVideoEntrega,
  precisaEscalar
} }];

const rawText = $('Parse AI Response').first().json.resposta || '';

if (!rawText || rawText.trim() === '') {
  return [];
}

let parts = rawText
  .split('|||')
  .map(p => p.trim())
  .filter(p => p.length > 0);

// TRAVA DE ORDEM
if (parts.length === 2) {
  const greetingPatterns = /^(olá|oi|bom dia|boa tarde|boa noite|tudo bem|meu nome)/i;
  const questionPatterns = /profissional de saúde|uso pessoal|especialidade|você (é|tem|já)/i;

  const part0IsQuestion = questionPatterns.test(parts[0]) && !greetingPatterns.test(parts[0]);
  const part1IsGreeting = greetingPatterns.test(parts[1]);

  if (part0IsQuestion && part1IsGreeting) {
    parts = [parts[1], parts[0]];
  }
}

// Limita a 3 partes máximo
if (parts.length > 3) {
  const first = parts[0];
  const second = parts[1];
  const rest = parts.slice(2).join(' ');
  parts = [first, second, rest];
}

// Retorna o texto e o cálculo de delay dinâmico
return parts.map(text => {
  const msgLength = text.length;
  // Delay base: 1.5s a 4s
  const baseDelay = Math.floor(Math.random() * 2500) + 1500; 
  // Tempo de "digitação" (20ms por caractere, máx 4s)
  const readingTime = Math.min(msgLength * 20, 4000); 
  const totalDelay = baseDelay + readingTime;

  return { 
    json: { 
      text: text,
      delay: totalDelay
    } 
  };
});

